import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { SlotMachineModuleParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/SlotMachineModuleParser';

export class SlotMachineModuleEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: Function) {
        super(callback, SlotMachineModuleParser);
    }

    public getParser(): SlotMachineModuleParser {
        return this.parser as SlotMachineModuleParser;
    }
}
